import 'dart:convert'; import 'package:injectable/injectable.dart'; import 'package:shared_preferences/shared_preferences.dart'; @singleton class NotificationLocalDatasource { final SharedPreferences _prefs; static const _key = 'notifications_v1'; NotificationLocalDatasource(this._prefs); Future<void> save(List<Map<String, dynamic>> data) => _prefs.setString(_key, jsonEncode(data)); List<Map<String, dynamic>> load() { final r = _prefs.getString(_key); if (r == null) return []; try { return List<Map<String, dynamic>>.from(jsonDecode(r)); } catch (_) { return []; } } Future<void> clear() => _prefs.remove(_key); }
